import type { Per100gNutrition, FoodLibraryItem, NutritionEntry, NutritionEstimate } from '@motivation/shared';
import { OpenFoodFactsService } from '../../../services/openfoodfacts.service.js';
import type { OFFProduct } from '../../../services/openfoodfacts.service.js';

export interface ServingValues {
    calories: number;
    protein_g: number;
    carbs_g: number;
    fat_g: number;
    fiber_g: number;
    sugar_g: number;
    sodium_mg: number;
}

export interface FoodServingFormData {
    /** Per-100g base values for proportional recalculation. Null when only fixed-serving data is available. */
    per100g: Per100gNutrition | null;
    /** Current serving nutrition (already scaled to servingAmount). */
    serving: ServingValues;
    /** Default serving amount — grams when servingByWeight is true, otherwise a multiplier. */
    servingAmount: number;
    /** True = grams mode with adaptive step sizes. False = multiplier mode (step = 1). */
    servingByWeight: boolean;
    /** Display label for multiplier mode (e.g. "1 serving"). */
    servingLabel?: string;
}

function scalePer100g(per100g: Per100gNutrition, grams: number): ServingValues {
    const s = (v: number) => Math.round(((v * grams) / 100) * 100) / 100;
    return {
        calories: s(per100g.calories),
        protein_g: s(per100g.protein_g),
        carbs_g: s(per100g.carbs_g),
        fat_g: s(per100g.fat_g),
        fiber_g: s(per100g.fiber_g ?? 0),
        sugar_g: s(per100g.sugar_g ?? 0),
        sodium_mg: s(per100g.sodium_mg ?? 0),
    };
}

function backCalcPer100g(serving: ServingValues, grams: number): Per100gNutrition {
    const scale = 100 / grams;
    return {
        calories: serving.calories * scale,
        protein_g: serving.protein_g * scale,
        carbs_g: serving.carbs_g * scale,
        fat_g: serving.fat_g * scale,
        fiber_g: serving.fiber_g * scale,
        sugar_g: serving.sugar_g * scale,
        sodium_mg: serving.sodium_mg * scale,
    };
}

function parseLibraryPer100g(item: FoodLibraryItem): Per100gNutrition | null {
    if (!item.per_100g_json) return null;
    try {
        return JSON.parse(item.per_100g_json) as Per100gNutrition;
    } catch {
        return null;
    }
}

export function offProductToFormData(product: OFFProduct): FoodServingFormData {
    const defaultGrams = OpenFoodFactsService.getDefaultServing(product);
    const per100g: Per100gNutrition = {
        calories: product.calories_per_100g,
        protein_g: product.protein_per_100g,
        carbs_g: product.carbs_per_100g,
        fat_g: product.fat_per_100g,
        fiber_g: product.fiber_per_100g,
        sugar_g: product.sugar_per_100g,
        sodium_mg: product.sodium_per_100g * 1000,
    };
    return {
        per100g,
        serving: scalePer100g(per100g, defaultGrams),
        servingAmount: defaultGrams,
        servingByWeight: true,
    };
}

export function libraryItemToFormData(item: FoodLibraryItem): FoodServingFormData {
    const per100g = parseLibraryPer100g(item);
    if (per100g) {
        const defaultGrams = item.serving_quantity && item.serving_quantity > 0
            ? Math.round(item.serving_quantity) : 100;
        return {
            per100g,
            serving: scalePer100g(per100g, defaultGrams),
            servingAmount: defaultGrams,
            servingByWeight: true,
        };
    }
    return {
        per100g: null,
        serving: {
            calories: item.calories ?? 0,
            protein_g: item.protein_g ?? 0,
            carbs_g: item.carbs_g ?? 0,
            fat_g: item.fat_g ?? 0,
            fiber_g: item.fiber_g ?? 0,
            sugar_g: item.sugar_g ?? 0,
            sodium_mg: item.sodium_mg ?? 0,
        },
        servingAmount: 1,
        servingByWeight: false,
        servingLabel: item.serving_label ?? '1 serving',
    };
}

/**
 * Extract grams (or ml, treated as g for per-100g math) from a serving-size
 * string. Handles "150g", "250 ml", "1 bar (45g)". Returns null for
 * non-numeric labels like "1 slice".
 */
function parseServingGrams(value: string | undefined): number | null {
    if (!value) return null;
    const paren = value.match(/\((\d+(?:\.\d+)?)\s*(?:g|ml)\)/i);
    if (paren) return Number.parseFloat(paren[1]);
    const plain = value.match(/(\d+(?:\.\d+)?)\s*(?:g|ml)\b/i);
    if (plain) return Number.parseFloat(plain[1]);
    return null;
}

export function nutritionEntryToFormData(entry: NutritionEntry): FoodServingFormData {
    const serving: ServingValues = {
        calories: entry.calories ?? 0,
        protein_g: entry.protein_g ?? 0,
        carbs_g: entry.carbs_g ?? 0,
        fat_g: entry.fat_g ?? 0,
        fiber_g: entry.fiber_g ?? 0,
        sugar_g: entry.sugar_g ?? 0,
        sodium_mg: entry.sodium_mg ?? 0,
    };
    const grams = parseServingGrams(entry.serving_size);
    if (grams !== null && grams > 0) {
        return {
            per100g: backCalcPer100g(serving, grams),
            serving,
            servingAmount: grams,
            servingByWeight: true,
        };
    }
    return {
        per100g: null,
        serving,
        servingAmount: 1,
        servingByWeight: false,
        servingLabel: entry.serving_size ?? undefined,
    };
}

export function estimateToFormData(estimate: NutritionEstimate): FoodServingFormData {
    const weight = estimate.estimated_weight_g > 0 ? estimate.estimated_weight_g : 100;
    const serving: ServingValues = {
        calories: estimate.calories,
        protein_g: estimate.protein_g,
        carbs_g: estimate.carbs_g,
        fat_g: estimate.fat_g,
        fiber_g: estimate.fiber_g,
        sugar_g: estimate.sugar_g,
        sodium_mg: 0,
    };
    return {
        per100g: backCalcPer100g(serving, weight),
        serving,
        servingAmount: weight,
        servingByWeight: true,
    };
}
